  3→/// Check if a peer is allowed to interact with the bot.
  4→///
  5→/// An empty allowlist means everyone is allowed (open policy).
  6→/// Entries are matched case-insensitively against the peer ID.
  7→/// Supports exact match and glob-style `*` wildcards.
  8→pub fn is_allowed(peer_id: &str, allowlist: &[String]) -> bool {
  9→    if allowlist.is_empty() {
 10→        return true;
 11→    }
 12→    let peer_lower = peer_id.to_lowercase();
 13→    allowlist.iter().any(|pattern| {
 14→        let pat = pattern.to_lowercase();
 15→        if pat.contains('*') {
 16→            glob_match(&pat, &peer_lower)
 17→        } else {
 18→            pat == peer_lower
 19→        }
 20→    })
 21→}
 22→
 23→/// Simple glob matching supporting `*` as a wildcard for any sequence of chars.
 24→fn glob_match(pattern: &str, text: &str) -> bool {
 25→    let parts: Vec<&str> = pattern.split('*').collect();
 26→    if parts.len() == 1 {
 27→        return pattern == text;
 28→    }
 29→
 30→    let mut pos = 0;
 31→    for (i, part) in parts.iter().enumerate() {
 32→        if part.is_empty() {
 33→            continue;
 34→        }
 35→        match text[pos..].find(part) {
 36→            Some(idx) => {
 37→                // First segment must match at start
 38→                if i == 0 && idx != 0 {
 39→                    return false;
 40→                }
 41→                pos += idx + part.len();
 42→            },
 43→            None => return false,
 44→        }
 45→    }
 46→    // Last segment must match at end (unless pattern ends with *)
 47→    if !parts.last().unwrap_or(&"").is_empty() {
 48→        pos == text.len()
 49→    } else {
 50→        true
 51→    }
 52→}
