102→    #[test]
103→    fn exact_match() {
104→        let list = vec!["alice".into(), "bob".into()];
105→        assert!(is_allowed("alice", &list));
106→        assert!(is_allowed("Alice", &list));
107→        assert!(!is_allowed("charlie", &list));
108→    }
