 3→/// Typed read-only view of common channel account config fields.
 4→///
 5→/// Each plugin's concrete config type (e.g. `TelegramAccountConfig`) implements
 6→/// this trait. The gateway and registry access typed fields instead of digging
 7→/// into raw `serde_json::Value`.
 8→///
 9→/// The store persists `Value` via `StoredChannel`. This trait is purely for
10→/// typed read access to shared config fields.
11→pub trait ChannelConfigView: Send + Sync + std::fmt::Debug {
12→    /// DM user/peer allowlist.
13→    fn allowlist(&self) -> &[String];
14→
15→    /// Group/chat ID allowlist.
16→    fn group_allowlist(&self) -> &[String];
17→
18→    /// DM access policy.
19→    fn dm_policy(&self) -> DmPolicy;
20→
21→    /// Group access policy.
22→    fn group_policy(&self) -> GroupPolicy;
23→
24→    /// Default model ID for this channel account.
25→    fn model(&self) -> Option<&str>;
26→
27→    /// Provider name associated with the model.
28→    fn model_provider(&self) -> Option<&str>;
29→
30→    // ── Per-channel / per-user override methods ─────────────────────────────
31→
32→    /// Model override for a specific channel/chat ID.
33→    fn channel_model(&self, _channel_id: &str) -> Option<&str> {
34→        None
35→    }
36→
37→    /// Provider override for a specific channel/chat ID.
38→    fn channel_model_provider(&self, _channel_id: &str) -> Option<&str> {
39→        None
40→    }
41→
42→    /// Model override for a specific user.
43→    fn user_model(&self, _user_id: &str) -> Option<&str> {
44→        None
45→    }
46→
47→    /// Provider override for a specific user.
48→    fn user_model_provider(&self, _user_id: &str) -> Option<&str> {
49→        None
50→    }
51→
52→    /// Resolve effective model: user > channel > account default.
53→    fn resolve_model(&self, channel_id: &str, user_id: &str) -> Option<&str> {
54→        self.user_model(user_id)
55→            .or_else(|| self.channel_model(channel_id))
56→            .or_else(|| self.model())
57→    }
58→
59→    /// Resolve effective provider: user > channel > account default.
60→    fn resolve_model_provider(&self, channel_id: &str, user_id: &str) -> Option<&str> {
61→        self.user_model_provider(user_id)
62→            .or_else(|| self.channel_model_provider(channel_id))
63→            .or_else(|| self.model_provider())
64→    }
65→}
