 25→/// Production channel registry with O(1) account→plugin routing.
 26→///
 27→/// The registry owns all channel plugins and maintains an account index
 28→/// for fast outbound routing. Lives in `crates/channels/` — no gateway
 29→/// dependency.
 30→///
 31→/// Plugins are stored behind `tokio::sync::RwLock` because `start_account`
 32→/// and `stop_account` are async (they may perform I/O during connection
 33→/// setup). The account index uses `std::sync::RwLock` since it is never
 34→/// held across await points.
 35→pub struct ChannelRegistry {
 36→    /// channel_type -> plugin instance (behind async RwLock for start/stop)
 37→    plugins: HashMap<String, Arc<RwLock<dyn ChannelPlugin>>>,
 38→    /// account_id -> channel_type for O(1) outbound routing
 39→    account_index: StdRwLock<HashMap<String, String>>,
 40→}
 41→
 42→impl Default for ChannelRegistry {
 43→    fn default() -> Self {
 44→        Self::new()
 45→    }
 46→}
 47→
 48→impl ChannelRegistry {
 49→    pub fn new() -> Self {
 50→        Self {
 51→            plugins: HashMap::new(),
 52→            account_index: StdRwLock::new(HashMap::new()),
 53→        }
 54→    }
 55→
 56→    /// Register a plugin by its `id()`.
 57→    #[instrument(skip(self, plugin))]
 58→    pub async fn register(&mut self, plugin: Arc<RwLock<dyn ChannelPlugin>>) {
 59→        let id = {
 60→            let p = plugin.read().await;
 61→            p.id().to_string()
 62→        };
 63→        self.plugins.insert(id, plugin);
 64→        #[cfg(feature = "metrics")]
 65→        gauge!(ch_metrics::ACTIVE).set(self.plugins.len() as f64);
 66→    }
 67→
 68→    /// Get a plugin by channel type identifier.
 69→    pub fn get(&self, channel_type: &str) -> Option<&Arc<RwLock<dyn ChannelPlugin>>> {
 70→        self.plugins.get(channel_type)
 71→    }
 72→
 73→    /// List all registered channel type identifiers.
 74→    pub fn list(&self) -> Vec<&str> {
 75→        self.plugins.keys().map(|s| s.as_str()).collect()
 76→    }
 77→
 78→    /// Start an account on the appropriate plugin and update the index.
 79→    #[instrument(skip(self, config), fields(channel_type, account_id))]
 80→    pub async fn start_account(
 81→        &self,
 82→        channel_type: &str,
 83→        account_id: &str,
 84→        config: serde_json::Value,
 85→    ) -> Result<()> {
 86→        let plugin = self
 87→            .plugins
 88→            .get(channel_type)
 89→            .ok_or_else(|| Error::invalid_input(format!("unknown channel type: {channel_type}")))?;
 90→
 91→        // Check for duplicate account_id across all channel types.
 92→        {
 93→            let index = self.account_index.read().unwrap_or_else(|e| e.into_inner());
 94→            if let Some(existing_ct) = index.get(account_id)
 95→                && existing_ct != channel_type
 96→            {
 97→                return Err(Error::invalid_input(format!(
 98→                    "account_id '{account_id}' already registered under channel type '{existing_ct}'"
 99→                )));
100→            }
101→        }
102→
103→        {
104→            let mut p = plugin.write().await;
105→            p.start_account(account_id, config).await?;
106→        }
107→
108→        {
109→            let mut index = self
110→                .account_index
111→                .write()
112→                .unwrap_or_else(|e| e.into_inner());
113→            index.insert(account_id.to_string(), channel_type.to_string());
114→        }
115→        Ok(())
116→    }
117→
118→    /// Stop an account and remove it from the index.
119→    #[instrument(skip(self), fields(channel_type, account_id))]
120→    pub async fn stop_account(&self, channel_type: &str, account_id: &str) -> Result<()> {
121→        let plugin = self
122→            .plugins
123→            .get(channel_type)
124→            .ok_or_else(|| Error::invalid_input(format!("unknown channel type: {channel_type}")))?;
125→
126→        {
127→            let mut p = plugin.write().await;
128→            p.stop_account(account_id).await?;
129→        }
130→
131→        {
132→            let mut index = self
133→                .account_index
134→                .write()
135→                .unwrap_or_else(|e| e.into_inner());
136→            index.remove(account_id);
137→        }
138→        Ok(())
139→    }
140→
141→    /// Resolve account_id → channel_type via the index.
142→    pub fn resolve_channel_type(&self, account_id: &str) -> Option<String> {
143→        let index = self.account_index.read().unwrap_or_else(|e| e.into_inner());
144→        index.get(account_id).cloned()
145→    }
146→
147→    /// Resolve an outbound sender for the given account.
148→    pub async fn resolve_outbound(&self, account_id: &str) -> Option<Arc<dyn ChannelOutbound>> {
149→        let channel_type = self.resolve_channel_type(account_id)?;
150→        let plugin = self.plugins.get(&channel_type)?;
151→        let p = plugin.read().await;
152→        Some(p.shared_outbound())
153→    }
154→
155→    /// Resolve a streaming outbound sender for the given account.
156→    pub async fn resolve_stream(&self, account_id: &str) -> Option<Arc<dyn ChannelStreamOutbound>> {
157→        let channel_type = self.resolve_channel_type(account_id)?;
158→        let plugin = self.plugins.get(&channel_type)?;
159→        let p = plugin.read().await;
160→        Some(p.shared_stream_outbound())
161→    }
162→
163→    /// List all active accounts as `(channel_type, account_id)` pairs.
164→    pub fn all_accounts(&self) -> Vec<(String, String)> {
165→        let index = self.account_index.read().unwrap_or_else(|e| e.into_inner());
166→        index
167→            .iter()
168→            .map(|(aid, ct)| (ct.clone(), aid.clone()))
169→            .collect()
170→    }
171→
172→    /// Probe health of all accounts across all plugins.
173→    #[instrument(skip(self))]
174→    pub async fn status_all(&self) -> Vec<ChannelHealthSnapshot> {
175→        let mut results = Vec::new();
176→        for (channel_type, plugin) in &self.plugins {
177→            let account_ids = {
178→                let p = plugin.read().await;
179→                p.account_ids()
180→            };
181→
182→            for account_id in account_ids {
183→                let p = plugin.read().await;
184→                let Some(status) = p.status() else {
185→                    continue;
186→                };
187→                match status.probe(&account_id).await {
188→                    Ok(snap) => results.push(snap),
189→                    Err(e) => {
190→                        warn!(channel_type, account_id, "health probe failed: {e}");
191→                        results.push(ChannelHealthSnapshot {
192→                            connected: false,
193→                            account_id: account_id.clone(),
194→                            details: Some(format!("probe error: {e}")),
195→                        });
196→                    },
197→                }
198→            }
199→        }
200→        results
201→    }
202→
203→    /// Get the typed config view for an account via the registry.
204→    pub async fn account_config(&self, account_id: &str) -> Option<Box<dyn ChannelConfigView>> {
205→        let channel_type = self.resolve_channel_type(account_id)?;
206→        let plugin = self.plugins.get(&channel_type)?;
207→        let p = plugin.read().await;
208→        p.account_config(account_id)
209→    }
210→
211→    /// Get the raw JSON config for an account via the registry.
212→    pub async fn account_config_json(&self, account_id: &str) -> Option<serde_json::Value> {
213→        let channel_type = self.resolve_channel_type(account_id)?;
214→        let plugin = self.plugins.get(&channel_type)?;
215→        let p = plugin.read().await;
216→        p.account_config_json(account_id)
217→    }
218→
219→    /// Fetch thread messages for context injection.
220→    ///
221→    /// Resolves the plugin for the given account and calls its thread context
222→    /// provider. Returns an empty vec if the plugin does not support threads.
223→    pub async fn fetch_thread_messages(
224→        &self,
225→        account_id: &str,
226→        channel_id: &str,
227→        thread_id: &str,
228→        limit: usize,
229→    ) -> Result<Vec<ThreadMessage>> {
230→        let channel_type = self
231→            .resolve_channel_type(account_id)
232→            .ok_or_else(|| Error::unknown_account(account_id))?;
233→        let plugin = self
234→            .plugins
235→            .get(&channel_type)
236→            .ok_or_else(|| Error::invalid_input(format!("unknown channel type: {channel_type}")))?;
237→        let p = plugin.read().await;
238→        match p.thread_context() {
239→            Some(ctx) => {
240→                ctx.fetch_thread_messages(account_id, channel_id, thread_id, limit)
241→                    .await
242→            },
243→            None => Ok(Vec::new()),
244→        }
245→    }
246→
247→    /// Update account config via the registry.
248→    pub async fn update_account_config(
249→        &self,
250→        account_id: &str,
251→        config: serde_json::Value,
252→    ) -> Result<()> {
253→        let channel_type = self
254→            .resolve_channel_type(account_id)
255→            .ok_or_else(|| Error::unknown_account(account_id))?;
256→        let plugin = self
257→            .plugins
258→            .get(&channel_type)
259→            .ok_or_else(|| Error::invalid_input(format!("unknown channel type: {channel_type}")))?;
260→        let p = plugin.read().await;
261→        p.update_account_config(account_id, config)
262→    }
263→
264→    /// Returns descriptors for all registered channel types.
265→    ///
266→    /// Parses each registered plugin ID as a [`ChannelType`] and returns its
267→    /// static descriptor. Unknown plugin IDs are silently skipped.
268→    pub fn descriptors(&self) -> Vec<ChannelDescriptor> {
269→        self.plugins
270→            .keys()
271→            .filter_map(|id| id.parse::<ChannelType>().ok())
272→            .map(|ct| ct.descriptor())
273→            .collect()
274→    }
275→}
