 53→/// Configuration for a single Discord bot account.
 54→#[derive(Clone, Serialize, Deserialize)]
 55→#[serde(default)]
 56→pub struct DiscordAccountConfig {
 57→    /// Discord bot token.
 58→    #[serde(serialize_with = "serialize_secret")]
 59→    pub token: Secret<String>,
 60→
 61→    /// DM access policy.
 62→    pub dm_policy: DmPolicy,
 63→
 64→    /// Group (guild channel) access policy.
 65→    pub group_policy: GroupPolicy,
 66→
 67→    /// Mention activation mode for guild channels.
 68→    pub mention_mode: MentionMode,
 69→
 70→    /// User allowlist (Discord user IDs or usernames).
 71→    pub allowlist: Vec<String>,
 72→
 73→    /// Guild allowlist (Discord guild/server IDs).
 74→    pub guild_allowlist: Vec<String>,
 75→
 76→    /// Default model ID for this channel account.
 77→    #[serde(skip_serializing_if = "Option::is_none")]
 78→    pub model: Option<String>,
 79→
 80→    /// Provider name associated with `model`.
 81→    #[serde(skip_serializing_if = "Option::is_none")]
 82→    pub model_provider: Option<String>,
 83→
 84→    /// Send bot responses as Discord replies to the user's message.
 85→    /// When false (default), responses are sent as standalone messages.
 86→    pub reply_to_message: bool,
 87→
 88→    /// Emoji reaction added to incoming messages while processing.
 89→    /// Set to `null`/omit to disable. Default: disabled.
 90→    #[serde(skip_serializing_if = "Option::is_none")]
 91→    pub ack_reaction: Option<String>,
 92→
 93→    /// Bot activity status text (e.g. "with AI").
 94→    /// When set, the bot displays a status like "Playing with AI".
 95→    #[serde(skip_serializing_if = "Option::is_none")]
 96→    pub activity: Option<String>,
 97→
 98→    /// Activity type: "playing", "listening", "watching", "competing", or "custom".
 99→    /// Default: "custom" when `activity` is set.
100→    #[serde(skip_serializing_if = "Option::is_none")]
101→    pub activity_type: Option<ActivityType>,
102→
103→    /// Bot online status: "online", "idle", "dnd", or "invisible".
104→    /// Default: "online".
105→    #[serde(skip_serializing_if = "Option::is_none")]
106→    pub status: Option<OnlineStatus>,
107→
108→    /// Enable OTP self-approval for non-allowlisted DM users (default: true).
109→    pub otp_self_approval: bool,
110→
111→    /// Cooldown in seconds after 3 failed OTP attempts (default: 300).
112→    pub otp_cooldown_secs: u64,
113→
114→    /// Per-channel model/provider overrides (channel_id -> override).
115→    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
116→    pub channel_overrides: HashMap<String, ChannelOverride>,
117→
118→    /// Per-user model/provider overrides (user_id -> override).
119→    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
120→    pub user_overrides: HashMap<String, UserOverride>,
121→}
