  8→/// Determine if an inbound message should be processed.
  9→///
 10→/// Returns `Ok(())` if the message is allowed, or `Err(reason)` if it should
 11→/// be silently dropped.
 12→pub fn check_access(
 13→    config: &TelegramAccountConfig,
 14→    chat_type: &ChatType,
 15→    peer_id: &str,
 16→    username: Option<&str>,
 17→    group_id: Option<&str>,
 18→    bot_mentioned: bool,
 19→) -> Result<(), AccessDenied> {
 20→    match chat_type {
 21→        ChatType::Dm => check_dm_access(config, peer_id, username),
 22→        ChatType::Group | ChatType::Channel => {
 23→            check_group_access(config, peer_id, group_id, bot_mentioned)
 24→        },
 25→    }
 26→}
 27→
 28→fn check_dm_access(
 29→    config: &TelegramAccountConfig,
 30→    peer_id: &str,
 31→    username: Option<&str>,
 32→) -> Result<(), AccessDenied> {
 33→    match config.dm_policy {
 34→        DmPolicy::Disabled => Err(AccessDenied::DmsDisabled),
 35→        DmPolicy::Open => Ok(()),
 36→        DmPolicy::Allowlist => {
 37→            // An empty allowlist with an explicit Allowlist policy means
 38→            // "deny everyone" — not "allow everyone".  The generic
 39→            // `is_allowed()` treats empty lists as open, so we
 40→            // short-circuit here.
 41→            if config.allowlist.is_empty() {
 42→                return Err(AccessDenied::NotOnAllowlist);
 43→            }
 44→            if gating::is_allowed(peer_id, &config.allowlist)
 45→                || username.is_some_and(|u| gating::is_allowed(u, &config.allowlist))
 46→            {
 47→                Ok(())
 48→            } else {
 49→                Err(AccessDenied::NotOnAllowlist)
 50→            }
 51→        },
 52→    }
 53→}
 54→
 55→fn check_group_access(
 56→    config: &TelegramAccountConfig,
 57→    _peer_id: &str,
 58→    group_id: Option<&str>,
 59→    bot_mentioned: bool,
 60→) -> Result<(), AccessDenied> {
 61→    match config.group_policy {
 62→        GroupPolicy::Disabled => return Err(AccessDenied::GroupsDisabled),
 63→        GroupPolicy::Allowlist => {
 64→            let gid = group_id.unwrap_or("");
 65→            if config.group_allowlist.is_empty()
 66→                || !gating::is_allowed(gid, &config.group_allowlist)
 67→            {
 68→                return Err(AccessDenied::GroupNotOnAllowlist);
 69→            }
 70→        },
 71→        GroupPolicy::Open => {},
 72→    }
 73→
 74→    // Mention gating
 75→    match config.mention_mode {
 76→        MentionMode::Always => Ok(()),
 77→        MentionMode::None => Err(AccessDenied::MentionModeNone),
 78→        MentionMode::Mention => {
 79→            if bot_mentioned {
 80→                Ok(())
 81→            } else {
 82→                Err(AccessDenied::NotMentioned)
 83→            }
 84→        },
 85→    }
 86→}
