245→    /// Security regression: removing the last entry from an allowlist must
246→    /// NOT silently switch to open access.  An explicit Allowlist policy with
247→    /// an empty list must deny every peer — by peer ID, by username, and in
248→    /// groups alike.  Failure here means unauthenticated users can bypass the
249→    /// allowlist by convincing an admin to remove all entries.
250→    #[test]
251→    fn security_removing_last_allowlist_entry_denies_access() {
252→        // --- DM: user is on the list, gets removed, must be denied ---
253→        let mut c = cfg();
