259→
260→        // Simulate admin removing the sole entry via the UI
261→        c.allowlist.clear();
262→
263→        // After removal: denied by peer ID alone
264→        assert_eq!(
265→            check_access(&c, &ChatType::Dm, "377114917", None, None, false),
266→            Err(AccessDenied::NotOnAllowlist),
267→            "empty DM allowlist must deny by peer_id"
268→        );
269→        // After removal: denied even when username is provided
270→        assert_eq!(
271→            check_access(&c, &ChatType::Dm, "377114917", Some("alice"), None, false),
272→            Err(AccessDenied::NotOnAllowlist),
273→            "empty DM allowlist must deny by username"
274→        );
275→        // After removal: other users also denied
276→        assert_eq!(
277→            check_access(&c, &ChatType::Dm, "999", Some("eve"), None, false),
278→            Err(AccessDenied::NotOnAllowlist),
279→            "empty DM allowlist must deny unknown users"
280→        );
281→
282→        // --- Group: same invariant ---
283→        let mut g = cfg();
284→        g.group_policy = GroupPolicy::Allowlist;
285→        g.group_allowlist = vec!["grp1".into()];
286→        g.mention_mode = MentionMode::Always;
287→
288→        assert!(check_access(&g, &ChatType::Group, "user", None, Some("grp1"), true).is_ok());
289→
290→        g.group_allowlist.clear();
291→
292→        assert_eq!(
293→            check_access(&g, &ChatType::Group, "user", None, Some("grp1"), true),
294→            Err(AccessDenied::GroupNotOnAllowlist),
295→            "empty group allowlist must deny previously-allowed group"
296→        );
297→        assert_eq!(
298→            check_access(&g, &ChatType::Group, "user", None, Some("grp2"), true),
299→            Err(AccessDenied::GroupNotOnAllowlist),
300→            "empty group allowlist must deny unknown groups"
301→        );
302→    }
