  8→/// Determine if an inbound message should be processed.
  9→///
 10→/// Returns `Ok(())` if the message is allowed, or `Err(reason)` if it should
 11→/// be silently dropped.
 12→pub fn check_access(
 13→    config: &DiscordAccountConfig,
 14→    chat_type: &ChatType,
 15→    peer_id: &str,
 16→    username: Option<&str>,
 17→    guild_id: Option<&str>,
 18→    bot_mentioned: bool,
 19→) -> Result<(), AccessDenied> {
 20→    match chat_type {
 21→        ChatType::Dm => check_dm_access(config, peer_id, username),
 22→        ChatType::Group | ChatType::Channel => check_guild_access(config, guild_id, bot_mentioned),
 23→    }
 24→}
 25→
 26→fn check_dm_access(
 27→    config: &DiscordAccountConfig,
 28→    peer_id: &str,
 29→    username: Option<&str>,
 30→) -> Result<(), AccessDenied> {
 31→    match config.dm_policy {
 32→        DmPolicy::Disabled => Err(AccessDenied::DmsDisabled),
 33→        DmPolicy::Open => Ok(()),
 34→        DmPolicy::Allowlist => {
 35→            if config.allowlist.is_empty() {
 36→                return Err(AccessDenied::NotOnAllowlist);
 37→            }
 38→            if gating::is_allowed(peer_id, &config.allowlist)
 39→                || username.is_some_and(|u| gating::is_allowed(u, &config.allowlist))
 40→            {
 41→                Ok(())
 42→            } else {
 43→                Err(AccessDenied::NotOnAllowlist)
 44→            }
 45→        },
 46→    }
 47→}
 48→
 49→fn check_guild_access(
 50→    config: &DiscordAccountConfig,
 51→    guild_id: Option<&str>,
 52→    bot_mentioned: bool,
 53→) -> Result<(), AccessDenied> {
 54→    match config.group_policy {
 55→        GroupPolicy::Disabled => return Err(AccessDenied::GuildsDisabled),
 56→        GroupPolicy::Allowlist => {
 57→            let gid = guild_id.unwrap_or("");
 58→            if config.guild_allowlist.is_empty()
 59→                || !gating::is_allowed(gid, &config.guild_allowlist)
 60→            {
 61→                return Err(AccessDenied::GuildNotOnAllowlist);
 62→            }
 63→        },
 64→        GroupPolicy::Open => {},
 65→    }
 66→
 67→    match config.mention_mode {
 68→        MentionMode::Always => Ok(()),
 69→        MentionMode::None => Err(AccessDenied::MentionModeNone),
 70→        MentionMode::Mention => {
 71→            if bot_mentioned {
 72→                Ok(())
 73→            } else {
 74→                Err(AccessDenied::NotMentioned)
 75→            }
 76→        },
 77→    }
 78→}
